const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// SURGERY - surg-acute-abdomen (15)
add('surg-acute-abdomen','A 35-year-old has periumbilical pain that migrated to the right iliac fossa over 12 hours with fever and rebound tenderness at McBurney point. WBC 14,000. What is the diagnosis and management?','Acute appendicitis; Alvarado score or CT abdomen to confirm; appendectomy (laparoscopic preferred) or antibiotic treatment for uncomplicated appendicitis','Appendicitis is the most common surgical emergency. Alvarado score ≥7 highly suggests appendicitis. CT has sensitivity >95%; ultrasound preferred in children and pregnant women to avoid radiation. APPAC trial: antibiotics alone feasible for uncomplicated appendicitis but higher recurrence rate.',4,'apply',['appendicitis','acute abdomen','appendectomy','Alvarado score','surgery']);
add('surg-acute-abdomen','What is peritonitis and how is it classified?','Peritonitis: inflammation of peritoneum; Primary: spontaneous bacterial peritonitis (cirrhosis); Secondary: perforated viscus, bowel perforation (most common); Tertiary: persistent peritonitis despite treatment','Secondary peritonitis from perforation presents with sudden onset severe abdominal pain, rigid abdomen, absent bowel sounds. Free air under diaphragm on erect CXR. Emergency surgical exploration for hollow viscus perforation.',3,'recall',['peritonitis','acute abdomen','SBP','bowel perforation','surgery']);
add('surg-acute-abdomen','A 65-year-old has sudden onset severe central abdominal pain, pulsatile abdominal mass, and hypotension. Diagnosis and management?','Ruptured abdominal aortic aneurysm (AAA); immediate transfer to OR — do NOT delay for CT if hemodynamically unstable; EVAR (endovascular) or open repair','AAA rupture has >80% mortality. Classic triad: severe tearing abdominal/back pain, pulsatile mass, hypotension. CT angiography only if hemodynamically stable. Permissive hypotension (target SBP 70-90 mmHg) until aortic control. Type O negative blood if crossmatch unavailable.',5,'analyze',['ruptured AAA','aortic aneurysm','EVAR','acute abdomen','surgery']);
add('surg-acute-abdomen','What are the signs and causes of bowel obstruction, and how is it managed?','SBO: adhesions (most common, prior surgery), hernias, malignancy; LBO: colorectal cancer, volvulus, diverticulitis; signs: colicky pain, distension, vomiting, obstipation; manage with NG tube, IV fluids, serial exams — surgery for strangulation or failed conservative management','CT abdomen is the investigation of choice for bowel obstruction. Water-soluble contrast gastrografin both diagnostic and therapeutic for adhesive SBO. Strangulation signs: fever, peritoneal signs, high WBC, CT findings — emergency surgery.',4,'apply',['bowel obstruction','SBO','adhesions','acute abdomen','surgery']);
add('surg-acute-abdomen','A 45-year-old woman has acute right upper quadrant pain radiating to the right shoulder, fever, and positive Murphy sign. WBC 16,000, alkaline phosphatase elevated. Diagnosis?','Acute cholecystitis; biliary colic with localized peritonitis; ultrasound confirms (gallstones, gallbladder wall thickening, pericholecystic fluid); treat with antibiotics + laparoscopic cholecystectomy (ideally within 72 hours)','Tokyo guidelines classify cholecystitis severity. Early laparoscopic cholecystectomy (within 72h) reduces complications compared to interval cholecystectomy. Complications: gangrenous cholecystitis, gallbladder perforation, Mirizzi syndrome. Acalculous cholecystitis in critically ill patients.',4,'apply',['acute cholecystitis','Murphy sign','cholecystectomy','gallstones','surgery']);
add('surg-acute-abdomen','What is Mirizzi syndrome?','Mirizzi syndrome: impacted stone in cystic duct or Hartmann pouch causing extrinsic compression of the common bile duct, resulting in obstructive jaundice — ERCP or surgery required','Mirizzi syndrome is a rare complication of cholelithiasis. Presents with jaundice, RUQ pain, and cholangitis. CT or MRCP for diagnosis. Cholecystectomy is the definitive treatment but may require hepaticojejunostomy in advanced cases.',3,'recall',['Mirizzi syndrome','biliary obstruction','cholecystitis','ERCP','surgery']);
add('surg-acute-abdomen','A 60-year-old with diverticulitis develops left lower quadrant pain, fever, and a tender palpable mass. CT shows pericolic abscess 5 cm. Management?','Acute diverticulitis with pericolic abscess; CT-guided percutaneous drainage for abscess >3 cm, IV antibiotics; elective sigmoid colectomy after resolution','Hinchey classification guides diverticulitis management: Stage I (pericolic abscess), Stage II (pelvic abscess) — percutaneous drainage; Stage III (purulent peritonitis), Stage IV (fecal peritonitis) — emergency surgery (Hartmann procedure). Elective laparoscopic colectomy after 6-8 weeks.',4,'analyze',['diverticulitis','abscess drainage','Hinchey classification','colectomy','surgery']);
add('surg-acute-abdomen','What is acute mesenteric ischemia and how is it classified?','Acute mesenteric ischemia: inadequate blood flow to small intestine; Types: arterial embolism (most common, 50%), arterial thrombosis, non-occlusive (NOMI), venous thrombosis; presents with severe pain out of proportion to exam','Diagnosis: CT mesenteric angiography (gold standard). Arterial embolism: transcatheter thrombolysis or surgical embolectomy. Bowel necrosis: emergency laparotomy with bowel resection. Mortality >60%. Peritonism = bowel infarction until proven otherwise.',5,'analyze',['mesenteric ischemia','bowel ischemia','CT angiography','acute abdomen','surgery']);
add('surg-acute-abdomen','What is the presentation and management of sigmoid volvulus?','Sigmoid volvulus: elderly/institutionalized patients, severe distension, coffee bean sign on AXR; manage with sigmoidoscopic decompression and rectal tube; sigmoid colectomy to prevent recurrence','Coffee bean sign (omega loop) on plain AXR is diagnostic of sigmoid volvulus. Sigmoidoscopic decompression effective in 80-90% without strangulation. Elective sigmoid colectomy is definitive treatment to prevent 50% recurrence. Cecal volvulus requires emergency right hemicolectomy.',4,'apply',['sigmoid volvulus','coffee bean sign','decompression','colectomy','surgery']);
add('surg-acute-abdomen','What is the differential diagnosis of right iliac fossa pain in a 25-year-old woman?','Appendicitis, ovarian pathology (ovarian cyst, torsion, ectopic pregnancy), PID, right ureteric colic, Meckel diverticulitis, terminal ileitis (Crohn disease), mesenteric adenitis','Pregnancy test is essential in women of childbearing age with RIF pain — ectopic pregnancy can be fatal. Pelvic ultrasound and CT abdomen/pelvis with contrast guide diagnosis. Diagnostic laparoscopy if imaging inconclusive.',3,'apply',['RIF pain','appendicitis differential','ectopic pregnancy','ovarian torsion','surgery']);
add('surg-acute-abdomen','What are the surgical indications in Crohn disease?','Bowel obstruction from stricture (fibrostenotic disease), intraabdominal abscess, fistula (enterocutaneous, enteroenteric, enterovesical), perforation, medically refractory disease, dysplasia/cancer — bowel-conserving approach preferred','Crohn surgery is not curative; recurrence in anastomosis common. Principles: resect minimal bowel, strictureplasty for multiple strictures, laparoscopic approach when possible. Preoperative optimization: nutritional support, steroid minimization, hold biologics perioperatively.',3,'recall',['Crohn disease surgery','strictureplasty','bowel-conserving','fistula','surgery']);
add('surg-acute-abdomen','A 70-year-old has sudden severe abdominal pain. AXR shows free air under the diaphragm. What is the immediate management?','Perforated viscus (most likely perforated peptic ulcer); resuscitate with IV fluids, IV antibiotics, IV PPI, NG decompression, urgent surgical consultation — emergency laparotomy for omental patch repair or Hartmann procedure','Free air under diaphragm confirms hollow viscus perforation. Erect CXR detects as little as 1-2 mL of free air. NSAID and H. pylori associated peptic ulcer perforation. Boerhaave syndrome (esophageal perforation from vomiting) — surgical emergency.',5,'analyze',['perforated viscus','free air','peptic ulcer perforation','acute abdomen','surgery']);
add('surg-acute-abdomen','What are the Ranson criteria for acute pancreatitis and their prognostic value?','On admission: age >55, WBC >16,000, glucose >11 mmol/L, LDH >350 IU/L, AST >250 IU/L; At 48h: Ca <2 mmol/L, hematocrit drop >10%, BUN rise >1.8 mmol/L, PaO2 <60, base deficit >4, fluid sequestration >6L — ≥3 criteria = severe disease','Ranson criteria predict acute pancreatitis severity at 48 hours. Higher scores correlate with increased morbidity and mortality. APACHE II and BISAP are more validated and can be calculated at any time. All scores should prompt ICU monitoring.',3,'recall',['Ranson criteria','pancreatitis severity','acute pancreatitis','surgery']);
add('surg-acute-abdomen','A 55-year-old has Hinchey Stage IV diverticulitis (fecal peritonitis). What is the surgical procedure?','Hartmann procedure: emergency sigmoid resection with end colostomy and oversewn rectal stump — colostomy reversal at 3-6 months when patient recovers','Hartmann procedure is the traditional approach for perforated diverticulitis with fecal contamination. Laparoscopic lavage and drainage is an option for Hinchey III (purulent) in hemodynamically stable patients. Primary anastomosis with ileostomy is increasingly used in experienced centers.',4,'apply',['Hartmann procedure','diverticulitis perforation','colostomy','surgery','acute abdomen']);
add('surg-acute-abdomen','What is the workup for acute abdominal pain — what investigations should be ordered?','Urine beta-hCG (women of childbearing age), CBC, BMP, lipase, LFTs, lactate, UA; erect CXR and AXR; CT abdomen/pelvis with contrast (IV ± oral depending on suspected diagnosis); pelvic ultrasound if gynaecologic cause suspected','CT abdomen/pelvis is the gold standard for most acute abdominal presentations. Ultrasound preferred for biliary and gynaecologic causes and in pregnancy. Lactate identifies mesenteric ischemia and bowel infarction. Lactate >2 mmol/L warrants urgent surgical evaluation.',2,'recall',['acute abdomen workup','CT abdomen','investigations','surgery']);

// SURGERY - surg-trauma (15)
add('surg-trauma','What is the primary survey in ATLS (Advanced Trauma Life Support)?','ABCDE: Airway (maintain with cervical spine precaution), Breathing (ventilation, tension pneumothorax), Circulation (hemorrhage control, shock), Disability (neurological status, GCS), Exposure (expose patient, prevent hypothermia)','ATLS primary survey focuses on immediately life-threatening injuries. Life-saving interventions are performed as problems are identified (not sequentially). Resuscitation occurs simultaneously with the survey. Secondary survey follows after stabilization.',2,'recall',['ATLS','primary survey','ABCDE','trauma assessment','surgery']);
add('surg-trauma','What is the diagnosis and management of tension pneumothorax?','Tension pneumothorax: dyspnea, absent ipsilateral breath sounds, tracheal deviation, hypotension, JVD; needle decompression 2nd intercostal space midclavicular line immediately, then chest tube','Tension pneumothorax is a clinical diagnosis — do NOT delay treatment for CXR. Needle decompression is temporizing; definitive treatment is chest tube (28-32Fr) in 5th intercostal space anterior axillary line (safe triangle). Mechanism: air accumulates under pressure, compresses mediastinum.',4,'apply',['tension pneumothorax','needle decompression','chest tube','ATLS','surgery']);
add('surg-trauma','A multiply-injured patient has hemoperitoneum on FAST exam and BP 80/50. What is the immediate next step?','Emergent laparotomy for hemorrhage control — permissive hypotension (SBP 80-90 mmHg) until surgical control, massive transfusion protocol (1:1:1 ratio PRBCs:FFP:platelets)','FAST (Focused Assessment with Sonography in Trauma) identifies intraperitoneal blood. Hemodynamically unstable patient with positive FAST → operating room. Damage control surgery: control bleeding and contamination first, pack abdomen, ICU resuscitation, then definitive repair.',5,'analyze',['FAST exam','hemoperitoneum','damage control surgery','massive transfusion','surgery','trauma']);
add('surg-trauma','What is damage control resuscitation (DCR) and its key components?','DCR: 1:1:1 ratio of PRBCs:FFP:platelets to correct coagulopathy, permissive hypotension until surgical control, early tranexamic acid (within 3h of injury), minimize crystalloids, prevent lethal triad (hypothermia, acidosis, coagulopathy)','CRASH-2 trial: tranexamic acid within 3 hours of injury reduces mortality from hemorrhage. The lethal triad (hypothermia <35°C, acidosis pH <7.3, coagulopathy INR >1.5) is a predictor of mortality. DCR replaces ATLS crystalloid-heavy approach.',4,'apply',['damage control resuscitation','DCR','massive transfusion','tranexamic acid','surgery','trauma']);
add('surg-trauma','What are the 4 classes of hemorrhagic shock and what defines Class III/IV?','Class I: <750 mL (<15%); Class II: 750-1500 mL (15-30%); Class III: 1500-2000 mL (30-40%) — altered consciousness, marked tachycardia, decreased BP; Class IV: >2000 mL (>40%) — immediately life-threatening, severe hypotension, mental obtundation','ATLS shock classification guides fluid resuscitation and blood product decisions. Class I-II may respond to crystalloid alone. Class III-IV require blood products. End-points: normalization of HR, MAP, urine output (0.5 mL/kg/h), lactate clearance.',3,'recall',['hemorrhagic shock','ATLS classification','blood loss','resuscitation','surgery']);
add('surg-trauma','What is a flail chest and how does it cause respiratory failure?','Flail chest: ≥3 consecutive ribs fractured in ≥2 places creating a free-floating segment; paradoxical breathing movement → poor respiratory mechanics; treat with positive pressure ventilation for respiratory failure, analgesia','Pulmonary contusion underneath flail segment is the primary cause of respiratory failure. Management: aggressive analgesia (epidural preferred), positive pressure ventilation if respiratory failure, surgical rib fixation for severe cases. Incentive spirometry and physiotherapy for mild cases.',4,'analyze',['flail chest','rib fracture','paradoxical breathing','pulmonary contusion','surgery','trauma']);
add('surg-trauma','What is the management of pelvic fractures with hemodynamic instability?','Pelvic binder immediately to reduce volume, MTP (massive transfusion protocol), angioembolization for arterial bleeding (IR) or pre-peritoneal pelvic packing (surgery) — external fixation for mechanical instability','Pelvic fractures can cause massive retroperitoneal hemorrhage (4-6L). Pelvic binder closes open book fractures, reducing pelvic volume and decreasing venous bleeding. CT angiography identifies arterial bleeding for embolization. Laparotomy contraindicated without pelvic bleeding control first.',5,'analyze',['pelvic fracture','hemorrhage control','pelvic binder','embolization','surgery','trauma']);
add('surg-trauma','What is the Glasgow Coma Scale (GCS) and how is it used in trauma?','GCS: Eye (4: spontaneous, 3: to voice, 2: to pain, 1: none) + Verbal (5-1) + Motor (6-1) = max 15; Mild TBI: GCS 13-15; Moderate: 9-12; Severe: ≤8','GCS ≤8 requires endotracheal intubation (cannot protect airway). GCS guides neurological monitoring and prognosis. ATLS primary survey uses GCS and pupillary responses in the Disability component. Serial GCS assessments detect deterioration.',2,'recall',['GCS','Glasgow Coma Scale','TBI','traumatic brain injury','ATLS','surgery']);
add('surg-trauma','What is a traumatic aortic injury and what are its clinical and imaging features?','Traumatic aortic injury: deceleration mechanism (MVA, fall from height); may be asymptomatic; CXR: widened mediastinum >8cm, loss of aortic knob, left apical cap; diagnose with CT angiography; treat with TEVAR (endovascular)','Aortic injury occurs at the isthmus (site of ligamentum arteriosum) — 90% of cases. Widened mediastinum on CXR has high sensitivity but low specificity. CT angiography confirms and grades injury. TEVAR has replaced open repair as standard of care.',4,'analyze',['aortic injury','widened mediastinum','TEVAR','deceleration injury','surgery','trauma']);
add('surg-trauma','What is the Ottawa Ankle Rule and when can ankle radiography be avoided?','Ottawa Ankle Rule: X-ray NOT needed if: no bony tenderness at posterior inferior tip of fibula or tibia, AND able to bear weight for 4 steps; SAVES up to 30-40% unnecessary radiographs','Ottawa Rules have 96-100% sensitivity for clinically significant fractures. Apply to patients ≥2 years old with normal mental status and no distracting injuries. Ottawa Foot Rule: tenderness at navicular or 5th metatarsal base requires X-ray.',2,'recall',['Ottawa Ankle Rule','ankle fracture','clinical decision rule','emergency medicine','surgery']);
add('surg-trauma','What is the NEXUS criteria and how does it help in cervical spine clearance?','NEXUS: cervical spine imaging NOT required if: no posterior midline tenderness, no focal neurological deficit, normal alertness, no intoxication, no distracting painful injury','NEXUS criteria allow clinical clearance of cervical spine without imaging in low-risk trauma patients, reducing unnecessary radiography. Canadian C-Spine Rule has higher specificity for identifying patients who need imaging. CT cervical spine indicated for all high-energy mechanism trauma with any NEXUS criterion present.',3,'apply',['cervical spine clearance','NEXUS','Canadian C-Spine Rule','trauma assessment','surgery']);
add('surg-trauma','A trauma patient develops sudden onset oliguria, increasing abdominal distension, and rising peak airway pressures on the ventilator post-laparotomy. What is the diagnosis?','Abdominal compartment syndrome (ACS): intraabdominal pressure >20 mmHg with new organ dysfunction; treat with decompressive laparotomy','ACS results from bowel edema, massive transfusion, abdominal packing, or reperfusion edema. Diagnosis: bladder pressure >20 mmHg x2 measurements. Decompressive laparotomy with temporary abdominal closure (vacuum dressing) is the treatment. Oliguria, respiratory failure, and cardiovascular compromise are cardinal features.',5,'analyze',['abdominal compartment syndrome','intraabdominal pressure','decompressive laparotomy','surgery','trauma']);
add('surg-trauma','What are the management principles for open fractures?','IV antibiotics within 1 hour (cefazolin ± gentamicin), tetanus prophylaxis, saline-soaked dressing, urgent orthopedic consultation; surgical debridement and washout within 6-8 hours; external fixation for unstable fractures','Gustilo-Anderson classification guides antibiotic duration: Type I-II: 24-48h cefazolin; Type III: 72h cefazolin + aminoglycoside ± metronidazole. Antibiotic prophylaxis and debridement timing are most important factors for infection prevention.',3,'apply',['open fracture','Gustilo-Anderson','IV antibiotics','debridement','surgery','trauma']);
add('surg-trauma','What is the role of the FAST exam in trauma and what does it assess?','FAST: Focused Assessment with Sonography in Trauma; assesses 4 windows: pericardial (cardiac tamponade), RUQ (hepatorenal space, Morrison pouch), LUQ (splenorenal), suprapubic (bladder/pelvis) — detects free fluid (blood)','FAST is a bedside screening tool for hemoperitoneum and hemopericardium in trauma. Sensitivity 85-90% for intraperitoneal fluid. Negative FAST does not exclude abdominal injury. Extended FAST (eFAST) adds bilateral thorax windows to assess for pneumothorax and hemothorax.',2,'recall',['FAST exam','trauma ultrasound','hemoperitoneum','pericardial tamponade','surgery']);
add('surg-trauma','A patient has a stab wound to the right chest. He is hemodynamically stable. CXR shows a moderate hemothorax. Management?','Chest tube (32-36Fr) in 5th intercostal space anterior axillary line (safe triangle); drain hemothorax to prevent clotted hemothorax; video-assisted thoracoscopy (VATS) for retained hemothorax','Hemothorax: blood in pleural space. Massive hemothorax: >1500 mL immediate drainage or >200 mL/h for 4h → thoracotomy. Tube thoracostomy drains hemothorax and allows monitoring of bleeding rate. VATS for retained/clotted hemothorax within 72-96h.',3,'apply',['hemothorax','chest tube','thoracostomy','VATS','surgery','trauma']);

// SURGERY - surg-breast (10)
add('surg-breast','A 55-year-old woman has a hard, irregular, non-tender breast lump. What is the triple assessment and what are the next steps?','Triple assessment: clinical examination + breast imaging (mammogram ± ultrasound) + tissue biopsy (core needle biopsy preferred) — all three should be concordant before treatment decision','Canadian Cancer Society guidelines recommend triple assessment as the standard for evaluating breast lumps. Core needle biopsy provides histological diagnosis, receptor status (ER, PR, HER2), and grade. Open surgical biopsy is rarely required. Concordant benign triple assessment = safe discharge with follow-up.',3,'apply',['breast cancer','triple assessment','core biopsy','mammogram','surgery']);
add('surg-breast','What are the breast cancer screening recommendations in Canada?','Mammogram every 2 years for women 50-74; discuss with women 40-49 (benefits and harms); high-risk women (BRCA, strong family history): annual MRI + mammogram starting at 30-40','CTFPHC (Canadian Task Force on Preventive Health Care) recommends routine screening mammography for 50-74 years. Women 40-49: individualized decision-making. High-risk screening (BRCA1/2, first-degree relative with BRCA, lifetime risk >25%): annual MRI + mammogram per Canadian Cancer Society.',2,'recall',['breast cancer screening','mammogram','BRCA','high-risk','surgery']);
add('surg-breast','A 45-year-old woman has a 2.5 cm breast cancer (ER+, HER2-) with 2 positive axillary lymph nodes (N1). What is the staging and systemic treatment?','Stage IIA-IIB (T2N1M0 or T1N1M0); systemic treatment: chemotherapy (AC-T) followed by endocrine therapy (tamoxifen or aromatase inhibitor x5-10 years)','Canadian breast cancer guidelines recommend adjuvant chemotherapy for node-positive ER+ breast cancer, especially in premenopausal patients. Aromatase inhibitors (letrozole, anastrozole) preferred for postmenopausal women. OncotypeDX genomic test may guide chemotherapy decision in node-negative HR+ HER2- disease.',4,'analyze',['breast cancer staging','adjuvant chemotherapy','tamoxifen','aromatase inhibitor','surgery']);
add('surg-breast','What is the sentinel lymph node biopsy (SLNB) and when is it used?','SLNB: injection of tracer (blue dye or radioisotope) identifies first draining lymph nodes in axilla — samples 1-5 nodes rather than full axillary dissection; used when clinically node-negative breast cancer','SLNB has replaced routine axillary lymph node dissection (ALND) for clinically node-negative breast cancer. Avoids unnecessary ALND and its complications (lymphedema, nerve damage, shoulder dysfunction). ALND only if SLNB positive with ≥3 positive nodes or node-positive after neoadjuvant chemotherapy.',3,'recall',['sentinel lymph node biopsy','SLNB','axillary lymph node','breast cancer surgery','surgery']);
add('surg-breast','What is the role of HER2-targeted therapy in breast cancer?','HER2-positive breast cancer (amplified by FISH or 3+ IHC): trastuzumab (Herceptin) for 1 year reduces recurrence by 50% — cardiotoxicity (monitor LVEF); pertuzumab + trastuzumab for node-positive disease','Canadian breast cancer guidelines recommend dual HER2 blockade (pertuzumab + trastuzumab + chemotherapy) for HER2+ node-positive or high-risk node-negative disease. T-DM1 for residual HER2+ disease after neoadjuvant chemotherapy. Cardiotoxicity: do not use concurrently with anthracyclines.',3,'apply',['HER2','trastuzumab','breast cancer treatment','pertuzumab','surgery']);
add('surg-breast','What is breast-conserving surgery (BCS) and when is mastectomy required?','BCS (lumpectomy + radiation) is equivalent to mastectomy for OS and DFS in eligible patients; mastectomy required for: multicentric disease, large tumor-to-breast ratio, inability to achieve clear margins, patient preference, radiation contraindication, inflammatory breast cancer','Milan trial established BCS + radiation equivalence to mastectomy. Clear margins (no ink on tumor) are required. Contralateral prophylactic mastectomy offered to BRCA1/2 carriers. Oncoplastic techniques improve cosmetic outcomes after BCS.',3,'recall',['breast-conserving surgery','mastectomy','lumpectomy','margins','surgery']);
add('surg-breast','What is inflammatory breast cancer and what is its management?','Inflammatory breast cancer: erythema, edema (peau d\'orange), warmth of ≥1/3 of breast skin — often misdiagnosed as mastitis; treat with neoadjuvant chemotherapy followed by mastectomy + radiation','Inflammatory breast cancer has the worst prognosis of all breast cancer subtypes (5-year survival ~40%). It is a clinical diagnosis — does not require skin lymphatic invasion on biopsy. Often presents without a palpable mass. NOT an indication for BCS.',4,'analyze',['inflammatory breast cancer','peau d orange','neoadjuvant chemotherapy','mastectomy','surgery']);
add('surg-breast','What is the hereditary breast cancer risk associated with BRCA1/2 mutations?','BRCA1: lifetime breast cancer risk 65-80%, ovarian cancer 39-46%; BRCA2: breast cancer 45-70%, ovarian cancer 11-27% — prophylactic mastectomy reduces risk by 90-95%','BRCA1/2 carriers should be referred to genetic counseling and hereditary cancer program. Risk-reducing interventions: bilateral prophylactic mastectomy (reduces breast cancer risk >90%), salpingo-oophorectomy (reduces ovarian and breast cancer risk). Surveillance: annual MRI + mammogram starting at 30.',3,'recall',['BRCA1 BRCA2','hereditary breast cancer','prophylactic mastectomy','genetic counseling','surgery']);
add('surg-breast','What is the treatment for locally advanced (Stage III) breast cancer?','Neoadjuvant chemotherapy (± HER2 or immunotherapy based on subtype) → surgery → radiation ± additional systemic therapy; goal: downstage tumor, assess chemotherapy response, increase BCS eligibility','Neoadjuvant chemotherapy for locally advanced breast cancer allows assessment of pathological complete response (pCR) — a prognostic marker. Triple-negative breast cancer: add pembrolizumab to neoadjuvant chemotherapy (KEYNOTE-522). HER2+: add pertuzumab + trastuzumab.',4,'analyze',['locally advanced breast cancer','neoadjuvant chemotherapy','pathological complete response','surgery']);
add('surg-breast','What are common benign breast conditions and how are they distinguished from malignancy?','Fibroadenoma (young women, rubbery smooth mobile), fibrocystic changes (cyclical pain, diffuse nodularity), breast abscess (periductal mastitis — smokers), fat necrosis (post-trauma/surgery), galactocele (lactating women)','Benign breast conditions are more common than cancer. Fibroadenomas: ultrasound-guided core biopsy if >2 cm or rapid growth; may be excised. Breast abscess: ultrasound-guided aspiration ± antibiotics; incision and drainage for large or recurrent abscesses. Triple assessment required for all suspicious lesions.',2,'recall',['benign breast disease','fibroadenoma','fibrocystic','breast abscess','surgery']);

// SURGERY - surg-periop (10)
add('surg-periop','What preoperative cardiac risk assessment is done for non-cardiac surgery?','Revised Cardiac Risk Index (RCRI): ischemic heart disease, congestive HF, cerebrovascular disease, diabetes on insulin, creatinine >177 μmol/L, high-risk surgery — 1 point each; RCRI ≥3 = major cardiac risk','CCS perioperative guidelines recommend RCRI calculation for all patients undergoing non-cardiac surgery. RCRI ≥3 → consider preoperative stress testing. Decision to test based on whether result would change management. Biomarker testing (troponin, BNP) adds prognostic information.',3,'apply',['preoperative assessment','RCRI','cardiac risk','non-cardiac surgery','surgery']);
add('surg-periop','When should antithrombotic medications be held before elective surgery?','Warfarin: hold 5 days pre-op; DOACs (apixaban, rivaroxaban): hold 24-48h (48-96h if high bleeding risk or CrCl <50 mL/min); ASA: continue unless high bleeding risk surgery (neurosurgery, intracranial, spinal); clopidogrel: hold 5-7 days','CCS perioperative antithrombotic guidelines balance thrombotic vs. bleeding risk. High VTE/thrombotic risk patients (mechanical valve, recent VTE, AF with prior stroke) may need bridging with LMWH. Recent PCI (within 6 months): consult cardiology.',4,'apply',['perioperative anticoagulation','warfarin','DOAC','antithrombotic','surgery']);
add('surg-periop','What is VTE prophylaxis in surgical patients?','Low-risk (minor procedure, ambulatory): early mobilization; Moderate-risk: LMWH or unfractionated heparin; High-risk (hip/knee arthroplasty, oncology surgery): LMWH or DOACs (rivaroxaban for THA/TKA); mechanical: compression stockings + IPC','CCS guidelines and Thrombosis Canada recommend pharmacological VTE prophylaxis for most surgical patients ≥40 years. Duration: general surgery 7-10 days; cancer surgery 28 days; major orthopedic surgery 35 days (DOACs preferred post-THA/TKA per CCS/ACCP).',3,'apply',['VTE prophylaxis','LMWH','perioperative','thromboprophylaxis','surgery']);
add('surg-periop','What is the significance of perioperative beta-blockade?','Continue beta-blockers if patient is already on them; do NOT start beta-blockers de novo in the perioperative period for high RCRI alone (POISE trial: reduced MI but increased stroke and death)','POISE trial showed initiating high-dose metoprolol on day of surgery increased 30-day mortality and stroke despite reducing MI. CCS guidelines: continue chronic beta-blockers, do not initiate unless patient is on them already or has compelling indication (rate control).',4,'analyze',['perioperative beta-blockers','POISE trial','cardiac protection','surgery']);
add('surg-periop','What is the approach to fasting before elective surgery?','Clear fluids: up to 2 hours before; solids and milk: 6 hours before (or 4h for light meal); NPO for emergency surgery','ASA and Canadian Anesthesiologists Society fasting guidelines: 2-4-6 rule. Prolonged fasting is not necessary for clear fluids and may worsen dehydration, anxiety, and hemodynamics. Preoperative carbohydrate loading (CHO drink 2h pre-op) in ERAS protocols reduces insulin resistance.',2,'recall',['preoperative fasting','NPO','anesthesia','ERAS','surgery']);
add('surg-periop','What are the components of an Enhanced Recovery After Surgery (ERAS) protocol?','Pre-op: carbohydrate loading, counseling; Intra-op: goal-directed fluid therapy, minimally invasive surgery, opioid-sparing analgesia, hypothermia prevention; Post-op: early oral feeding, early mobilization, multimodal analgesia, VTE prophylaxis','ERAS protocols reduce length of stay by 2-3 days, complications, and costs without compromising outcomes. Originally developed for colorectal surgery, now applied to many specialties. Core elements: minimal opioids, early feeding, early ambulation, and standardized perioperative care.',2,'recall',['ERAS','enhanced recovery','perioperative care','length of stay','surgery']);
add('surg-periop','How is a patient\'s surgical risk classified per American Society of Anesthesiologists (ASA) classification?','ASA I: healthy; ASA II: mild systemic disease; ASA III: severe systemic disease; ASA IV: severe systemic disease that is a constant threat to life; ASA V: moribund, not expected to survive without surgery; ASA VI: brain dead','ASA classification correlates with perioperative mortality. ASA III-IV patients require thorough preoperative optimization and monitoring. ASA IV-V patients should have goals of care discussion. Emergency suffix (E) added for emergency procedures.',1,'recall',['ASA classification','surgical risk','perioperative','anesthesia','surgery']);
add('surg-periop','What are the principles of perioperative management of diabetic patients?','Hold oral hypoglycemics (metformin 48h before, SGLT2i 3-4 days before); continue insulin (reduce to 50-80% of basal dose while NPO); monitor glucose q1-2h; target glucose 5-10 mmol/L intraoperatively','SGLT2 inhibitors must be stopped before surgery to prevent euglycemic DKA. Metformin held due to lactic acidosis risk if AKI develops. Insulin-dependent patients should not have their basal insulin completely stopped. CDA/Diabetes Canada perioperative guidelines.',3,'apply',['perioperative diabetes','SGLT2i','metformin','insulin management','surgery']);
add('surg-periop','What is the approach to managing antiplatelet therapy in a patient with coronary stents requiring elective surgery?','BMS: defer elective surgery ≥1 month (ideally 3 months); DES: defer elective surgery ≥6 months (ideally 12 months); if surgery cannot be deferred: continue ASA, hold only clopidogrel with cardiology consultation','CCS perioperative guidelines recommend that surgery should ideally be deferred until dual antiplatelet therapy can be discontinued safely. If emergent surgery required: continue ASA, restart antiplatelet ASAP post-op. Risk of stent thrombosis vs. perioperative hemorrhage must be balanced.',4,'analyze',['coronary stent','perioperative antiplatelet','DES','BMS','surgery']);
add('surg-periop','What are the criteria for discontinuing a perioperative blood transfusion trigger in surgical patients?','Restrictive transfusion: target Hgb 70-80 g/L (transfuse when Hgb <70) for most surgical patients; Hgb <80 for high-risk cardiac patients; pre-op autologous donation, intraoperative cell salvage to reduce allogeneic transfusion','TRICC, FOCUS, and TRICS trials support restrictive transfusion strategy. Restrictive strategy non-inferior to liberal strategy for most patients. Pre-operative anemia management (IV iron, ESA) should be optimized before elective surgery to minimize transfusion requirement.',3,'recall',['blood transfusion','transfusion trigger','restrictive strategy','perioperative','surgery']);

// PEDIATRICS - peds-development (15)
add('peds-development','A 2-year-old does not respond to his name, avoids eye contact, has no words, and engages in repetitive play. What is the diagnosis and appropriate referral?','Autism Spectrum Disorder (ASD); refer immediately to developmental pediatrics + speech therapy; do not wait','CPS (Canadian Paediatric Society) recommends immediate referral for any child with language regression, no words by 12 months, no 2-word phrases by 24 months, loss of any skills at any age, or persistent social communication concerns. Early intervention improves outcomes dramatically.',4,'apply',['autism','ASD','developmental delay','referral','pediatrics']);
add('peds-development','What are the typical developmental milestones for a 12-month-old?','Gross motor: pulls to stand, cruises; Fine motor: pincer grasp; Language: says mama/dada (specific), 2-3 other words; Social: waves bye-bye, plays peek-a-boo, stranger anxiety','CPS developmental surveillance at all well-child visits. Red flags at 12 months: no babbling, no pointing/waving, no words, no social smile. Development follows cephalocaudal and proximal-distal sequence.',2,'recall',['milestones','12 months','gross motor','language development','pediatrics']);
add('peds-development','What developmental milestones should a 2-year-old achieve?','Gross motor: runs, kicks ball, climbs stairs with 2 feet per step; Fine motor: scribbles, towers of 6 blocks; Language: ≥50 words, 2-word phrases, 50% intelligible to strangers; Social: parallel play','CPS developmental assessment at 18 months and 24 months. Red flags at 2 years: <50 words, no 2-word combinations, failure to follow 2-step commands. Regression is always a red flag.',2,'recall',['2-year milestones','language','2-word phrases','parallel play','pediatrics']);
add('peds-development','What language milestones are expected at 3 years and 4 years?','3 years: 200+ words, 3-word sentences, 75% intelligible; asks who/what/where; 4 years: 1000+ words, 4-6 word sentences, 100% intelligible to strangers; tells stories, asks why','CPS speech milestones: refer to speech-language pathology if ≤50 words at 24 months, not combining 2 words by 24 months, or <75% intelligible at 36 months. Bilingual children may have slightly slower single-language acquisition but total vocabulary across both languages is normal.',2,'recall',['language milestones','3 years','4 years','speech delay','pediatrics']);
add('peds-development','What is the significance of loss of previously acquired milestones (regression)?','Any developmental regression is a red flag requiring urgent assessment — may indicate Rett syndrome (girls), autism, epileptic encephalopathy (Landau-Kleffner), metabolic disorders, or mass lesion','CPS guidelines: parental concern about developmental regression must always be taken seriously. Rett syndrome: normal development to 6-18 months then regression with loss of purposeful hand use, development of hand stereotypies. Metabolic conditions may present with regression.',4,'analyze',['developmental regression','red flag','Rett syndrome','autism','pediatrics']);
add('peds-development','What screening tools are used in Canada for developmental surveillance?','ASQ (Ages and Stages Questionnaires): 2, 4, 6, 9, 12, 18, 24, 30, 36 months; M-CHAT-R (Modified Checklist for Autism): 18 and 24 months; Denver Developmental Screening Test II','CPS recommends developmental surveillance at every well-child visit using standardized tools. ASQ is a validated parent-completed questionnaire. Positive M-CHAT-R (score ≥3) requires follow-up; ≥8 = immediate referral to developmental pediatrics.',2,'recall',['developmental screening','ASQ','M-CHAT','developmental surveillance','pediatrics']);
add('peds-development','A 7-year-old has difficulty concentrating, hyperactivity, and impulsivity both at home and school. DSM-5 criteria are met. Diagnosis and management?','ADHD; multimodal treatment: behavioral therapy first (age <6), then methylphenidate (first-line stimulant medication for age ≥6) + behavioral therapy; school accommodations','CPS ADHD guidelines: ADHD requires symptoms in ≥2 settings (home and school), before age 12, for ≥6 months. Stimulants (methylphenidate, amphetamines) are most effective pharmacotherapy. Non-stimulants (atomoxetine, guanfacine) for stimulant intolerance or substance abuse concern.',3,'apply',['ADHD','methylphenidate','stimulants','behavioral therapy','pediatrics']);
add('peds-development','What is the developmental assessment for a 5-year-old starting school?','Gross motor: hops, skips, catches ball; Fine motor: prints letters, draws person with 6 parts; Language: 5+ word sentences, full sentences, grammar; Social: cooperative play, understands rules; Cognitive: counts to 10, knows colors','School readiness requires assessment of cognitive, language, motor, social-emotional, and self-care domains. CPS recommends 4-5 year visit focusing on school readiness. Phonological awareness (rhyming, letter sounds) predicts reading development.',2,'recall',['school readiness','5-year milestones','kindergarten','developmental assessment','pediatrics']);
add('peds-development','What is cerebral palsy (CP) and how is it classified?','CP: permanent disorder of movement and posture from non-progressive brain injury early in development; classified by: motor type (spastic most common 85%, dyskinetic, ataxic), topography (hemiplegia, diplegia, quadriplegia), GMFCS level','CP diagnosis: clinical, no single test. Risk factors: prematurity (highest), perinatal asphyxia, infection. MRI brain confirms lesion (periventricular leukomalacia in preterm). Management: multidisciplinary — physio, OT, speech, orthotics, medications (baclofen for spasticity, botulinum toxin).',3,'recall',['cerebral palsy','spastic CP','GMFCS','developmental disability','pediatrics']);
add('peds-development','What is the expected gross motor development in the first year of life?','2 months: lifts head prone; 4 months: head control, rolls; 6 months: sits with support; 9 months: sits unsupported, stands with support; 12 months: pulls to stand, cruises, possibly walking','CPS developmental surveillance: if not walking by 18 months → referral. 10% of children walk by 9 months, 50% by 12 months, 90% by 15 months. Independent walking after 18 months is a developmental delay requiring evaluation.',2,'recall',['gross motor milestones','first year','motor development','walking','pediatrics']);
add('peds-development','What are the features and management of a child with intellectual disability (ID)?','ID: IQ <70 + adaptive behavior deficits in ≥2 areas (communication, self-care, home living, social skills); etiological workup: chromosomal microarray (first-line for unexplained ID), metabolic screen, MRI','CPS recommends chromosomal microarray as first-line for unexplained developmental delay/ID — identifies cause in 15-20%. Fragile X testing in males with ID. Management: early intervention services, school support, behavioral therapies, treat comorbidities (epilepsy, ADHD, ASD).',3,'apply',['intellectual disability','developmental delay','chromosomal microarray','pediatrics']);
add('peds-development','What social-emotional milestones are expected in infancy?','0-2 months: social smile; 2-3 months: coos, vocalizes; 4-6 months: laughs, reaches for caregiver; 9 months: stranger anxiety, separation anxiety, object permanence; 12 months: joint attention, pointing','Joint attention (following another person\'s gaze to an object and sharing that attention) develops at 9-12 months and is critical for language development. Absence of joint attention by 12 months is a red flag for autism spectrum disorder.',2,'recall',['social-emotional milestones','joint attention','stranger anxiety','autism red flags','pediatrics']);
add('peds-development','What is the role of lead screening in pediatric developmental assessment?','Blood lead level testing at age 1-2 years in high-risk children: urban living, older housing (pre-1978), pica, immigrant from endemic country — elevated lead (>5 μg/dL) causes cognitive impairment','No safe level of blood lead exists. Sources: old paint (most common in Canada), imported ceramics, certain traditional medicines, water pipes. Treatment: chelation therapy (succimer DMSA) for blood lead >45 μg/dL. Primary prevention: blood lead level check, education.',3,'apply',['lead poisoning','developmental delay','blood lead level','chelation','pediatrics']);
add('peds-development','What is normal developmental variation versus delay in walking?','Normal: most children walk independently by 14-15 months; variation up to 18 months is normal if other milestones normal, no neurological signs, and positive family history of late walking; refer if not walking by 18 months','Bottom shufflers and commando crawlers often walk later (up to 18 months) and have a family history. CPS: investigate late walking with developmental assessment, hip X-ray, and creatine kinase (DMD). Duchenne muscular dystrophy: X-linked, toe-walking, Gowers sign.',3,'apply',['late walking','developmental variation','Duchenne muscular dystrophy','pediatrics']);
add('peds-development','What is the management of a child with suspected learning disability?','Formal psychoeducational assessment, vision and hearing screening, ADHD evaluation; school accommodation plan (IEP); evidence-based educational interventions (reading: phonics-based, Orton-Gillingham for dyslexia)','Learning disabilities affect 5-15% of school-age children. Most common: dyslexia (reading disability). CPS recommends standardized psychoeducational testing by psychologist to diagnose learning disability and guide accommodations. Early identification and intervention are critical.',3,'apply',['learning disability','dyslexia','IEP','psychoeducational assessment','pediatrics']);

// PEDIATRICS - peds-fever (15)
add('peds-fever','A 2-month-old presents with fever of 38.5°C rectally. What is the management?','Fever ≥38°C in infant <2 months requires full sepsis workup (CBC, blood culture, UA + urine culture, LP) and empiric IV antibiotics (ampicillin + gentamicin ± acyclovir) regardless of clinical appearance','CPS guidelines: fever in neonates (<28 days) and young infants (28-90 days) is a medical emergency. All infants <28 days with fever require hospitalization. 28-60 day infants: risk stratification with Rochester/PECARN criteria. Well-appearing low-risk 2-3 month infants may be managed with observation.',5,'analyze',['fever in infants','neonatal fever','sepsis workup','empiric antibiotics','pediatrics']);
add('peds-fever','A 2-year-old has fever 40°C, bulging tympanic membrane, and purulent ear discharge. Diagnosis and treatment?','Acute otitis media (AOM); first-line treatment: amoxicillin 90 mg/kg/day (divided TID) x10 days for children <2 years or severe disease — 5-7 days for older children with mild disease','CPS AOM guidelines recommend high-dose amoxicillin as first-line (covers penicillin non-susceptible S. pneumoniae). Watchful waiting for 48-72h acceptable for mild AOM in children ≥6 months with unilateral disease. Amoxicillin-clavulanate for treatment failure or recurrent AOM.',3,'apply',['acute otitis media','AOM','amoxicillin','fever','pediatrics']);
add('peds-fever','What are the most common causes of fever without localizing source in children aged 3-36 months?','Occult bacteremia (less common post-PCV13 vaccine era), UTI (most common serious bacterial infection), viral illness (most common overall), pneumonia; S. pneumoniae most common organism in bacteremia','CPS guidelines for fever without source: age 3-36 months with fever ≥39°C — if well-appearing and vaccinated, watchful waiting is appropriate. Urinalysis and urine culture for all febrile girls <2 years and boys <6 months. Blood culture if appearing ill.',3,'apply',['fever without source','occult bacteremia','UTI','pediatric fever','pediatrics']);
add('peds-fever','What clinical features suggest serious bacterial infection (SBI) in a febrile child?','High temperature (≥39°C in <3 months or ≥40°C in 3-36 months), toxic appearance (lethargy, poor perfusion, inconsolable irritability), ill-appearing despite antipyretics, petechial/purpuric rash, neck stiffness','NICE traffic-light system: green (low risk), amber (intermediate), red (high risk) features for SBI. CPS guidelines: petechiae + fever = meningococcemia until proven otherwise — give IV ceftriaxone immediately and admit.',3,'apply',['serious bacterial infection','toxic appearance','meningococcemia','fever assessment','pediatrics']);
add('peds-fever','A 3-year-old has fever, sore throat, and a beefy red pharynx with exudates and swollen anterior cervical nodes. Rapid antigen test for Group A Strep is positive. Treatment?','Group A Streptococcal pharyngitis; treat with amoxicillin 50 mg/kg/day x10 days (or penicillin V) to prevent rheumatic fever — penicillin/amoxicillin is first-line; azithromycin if penicillin allergy','CPS guidelines: antibiotics for GAS pharyngitis confirmed by rapid antigen test or throat culture. Centor/McIsaac criteria for clinical probability. Treat to prevent acute rheumatic fever (ARF). ARF prevention requires 10 days of penicillin-class antibiotics.',3,'apply',['GAS pharyngitis','strep throat','amoxicillin','rheumatic fever prevention','pediatrics']);
add('peds-fever','What is the management of a 6-year-old with suspected epiglottitis presenting with drooling, dysphagia, and respiratory distress?','Do NOT examine throat or agitate child; call anesthesia and ENT immediately; maintain airway in OR with intubation; IV ceftriaxone (H. influenzae type b and S. pneumoniae coverage)','Epiglottitis is rare post-Hib vaccine but still occurs. Classic: sudden onset, high fever, drooling, tripod position, stridor (may not be present). Do NOT attempt to examine oropharynx — may precipitate complete obstruction. Lateral neck X-ray: "thumbprint sign" (edematous epiglottis).',5,'analyze',['epiglottitis','airway emergency','drooling','Hib vaccine','pediatrics']);
add('peds-fever','A 5-year-old has a fever, strawberry tongue, diffuse erythematous rash that feels like sandpaper, and desquamation of palms and soles. What is the diagnosis and treatment?','Scarlet fever (Group A Streptococcal infection with erythrogenic toxin); treat with amoxicillin or penicillin x10 days','Scarlet fever is caused by erythrogenic toxin-producing GAS. Pastia lines (accentuation of rash in skin folds). Sandpaper rash is characteristic. Complications without treatment: ARF, glomerulonephritis. Throat culture or rapid antigen test confirms diagnosis.',3,'apply',['scarlet fever','GAS','strawberry tongue','sandpaper rash','pediatrics']);
add('peds-fever','What are the diagnostic criteria for Kawasaki disease and how is it treated?','Fever ≥5 days + ≥4 of 5: bilateral conjunctivitis, mucous membrane changes (strawberry tongue, cracked lips), polymorphous rash, extremity changes (erythema/desquamation), cervical lymphadenopathy; treat with IVIG 2g/kg + ASA','CPS Kawasaki guidelines: treat within 10 days of fever onset. IVIG reduces coronary artery aneurysm from 25% to 3-5%. High-dose ASA for anti-inflammatory effect, then low-dose for antiplatelet effect. Coronary artery imaging (echocardiogram) at diagnosis, 2 weeks, and 6-8 weeks.',4,'apply',['Kawasaki disease','IVIG','coronary aneurysm','fever','pediatrics']);
add('peds-fever','A 9-month-old develops fever then rapid defervescence followed by a rose-colored rash on the trunk. Diagnosis?','Roseola infantum (HHV-6); self-limited viral illness — fever 3-5 days, then rash after fever resolves; no specific treatment required','Roseola is caused by HHV-6 (human herpesvirus 6). Most common exanthem in infants 6-24 months. The rash appears as fever resolves — this pattern is diagnostic. Febrile seizures can occur during the high fever phase. HHV-7 also causes roseola. Reassurance and supportive care.',2,'recall',['roseola','HHV-6','infantum','pediatric viral illness','pediatrics']);
add('peds-fever','What is the approach to fever management in pediatrics — when should antipyretics be given?','Antipyretics for comfort (not to prevent febrile seizures); acetaminophen 15 mg/kg q4-6h OR ibuprofen 10 mg/kg q6-8h (≥6 months); do NOT use aspirin (Reye syndrome risk)','CPS guidelines: fever is a beneficial host response to infection. Antipyretics improve child comfort but do not reduce febrile seizure risk. Ibuprofen is more effective than acetaminophen for fever reduction. Tepid sponging is not recommended. Never use ASA in children due to Reye syndrome.',2,'recall',['fever management','acetaminophen','ibuprofen','Reye syndrome','pediatrics']);
add('peds-fever','A 4-year-old with high fever and a petechial rash has rapid clinical deterioration with hypotension. What is the diagnosis and immediate treatment?','Meningococcemia (Neisseria meningitidis); IV ceftriaxone 100 mg/kg immediately (do not wait for LP), aggressive fluid resuscitation, ICU admission','Meningococcal septicemia is the most dangerous pediatric infection — death within hours. Non-blanching petechiae + fever = meningococcemia until proven otherwise. Give ceftriaxone BEFORE any other investigation if patient is deteriorating. Rifampin or ciprofloxacin prophylaxis for close contacts.',5,'analyze',['meningococcemia','purpura fulminans','ceftriaxone','petechiae','pediatrics']);
add('peds-fever','What is the workup and management of UTI in a febrile child under 2 years?','Urine sample (catheter or suprapubic for <2 years); UA + culture; treat empiric trimethoprim-sulfamethoxazole (TMP-SMX) or nitrofurantoin — 7-14 days for febrile UTI; renal ultrasound for all first febrile UTIs','CPS UTI guidelines: clean-catch urine is unreliable in infants — use catheter or SPA. Febrile UTI (pyelonephritis) requires 10-14 day treatment. First febrile UTI: renal ultrasound. VCUG (voiding cystourethrogram) for abnormal ultrasound or recurrent UTI to detect VUR.',3,'apply',['pediatric UTI','urinary tract infection','febrile UTI','renal ultrasound','VCUG','pediatrics']);
add('peds-fever','What is hand, foot, and mouth disease (HFMD) and how is it managed?','HFMD: Coxsackievirus A16 or Enterovirus 71; painful vesicles on hands, feet, mouth; low-grade fever; self-limited 7-10 days — supportive care, analgesia for mouth pain','HFMD is highly contagious (fecal-oral, droplet). School exclusion until child is well and vesicles have crusted. No vaccine available in Canada. EV71 associated with neurological complications (brainstem encephalitis, pulmonary edema) — more common in Asia.',2,'recall',['hand foot mouth disease','Coxsackievirus','enterovirus','HFMD','pediatrics']);
add('peds-fever','A 10-year-old presents with fever, joint pain/swelling (knee, ankle) that migrated from the ankles to the knees, and a new heart murmur. What is the diagnosis?','Acute rheumatic fever (ARF); Jones criteria: 2 major OR 1 major + 2 minor criteria with evidence of prior GAS infection (elevated ASO titer, throat culture)','Major Jones criteria: carditis, migratory polyarthritis, Sydenham chorea, erythema marginatum, subcutaneous nodules. Minor: fever, elevated ESR/CRP, prolonged PR interval. ARF prevention: treat GAS pharyngitis. Secondary prophylaxis: monthly benzathine penicillin G for 10 years (or until age 25 if carditis).',4,'analyze',['acute rheumatic fever','ARF','Jones criteria','GAS','carditis','pediatrics']);
add('peds-fever','What are the indications for hospitalization of a febrile child?','Age <28 days (all), age 28-60 days if not meeting low-risk criteria, toxic appearance, petechiae, signs of sepsis, failed outpatient treatment, immunocompromised, parental inability to monitor','CPS fever guidelines: all neonates (<28 days) with fever require hospitalization. For 28-60 day age group: Rochester/PECARN low-risk criteria must be fully met for outpatient management. Ensure reliable follow-up and parent education for all discharged febrile infants.',3,'apply',['hospitalization criteria','febrile infant','neonatal fever','age thresholds','pediatrics']);

// PEDIATRICS - peds-neonate (15)
add('peds-neonate','A newborn has Apgar scores of 5 at 1 minute and 7 at 5 minutes. What does this mean and what interventions are needed?','Apgar 5 at 1 min = intermediate (interventions needed); 7 at 5 min = reassuring; interventions: dry, stimulate, position airway, suction if needed, supplemental O2','Apgar score: Appearance (color), Pulse, Grimace (reflex), Activity (tone), Respiration — scored 0-2 each (max 10). Score <7 at 5 minutes requires intervention and repeat scoring. Score <3 requires neonatal resuscitation. CPS NRP (Neonatal Resuscitation Program) guidelines.',3,'apply',['Apgar score','neonatal assessment','newborn resuscitation','NRP','pediatrics']);
add('peds-neonate','A term newborn requires resuscitation. After drying, stimulating, and positioning, HR is 60 bpm and infant is not breathing. What is the next step?','Positive pressure ventilation (PPV) with room air (21% O2 initially for term infants) using bag-valve-mask — if HR does not improve within 30 seconds, assess for proper mask seal and chest rise','CPS NRP 2021: initial resuscitation with air (21%) for term infants; titrate O2 up if HR not improving. Effective PPV: rate 40-60 breaths/min, look for chest rise, HR should increase within 30 seconds. Endotracheal intubation if PPV ineffective or prolonged.',4,'apply',['neonatal resuscitation','PPV','NRP','newborn','pediatrics']);
add('peds-neonate','What is neonatal hypoglycemia and how is it defined and managed?','Neonatal hypoglycemia: blood glucose <2.6 mmol/L in term infants in first 48h; at-risk: IDM, SGA, LGA, preterm, post-asphyxia; treat with early feeding (BF or formula) or IV dextrose 10% (2 mL/kg bolus if symptomatic)','CPS neonatal glucose guidelines: all at-risk newborns should have glucose screening in first 30-60 minutes. Asymptomatic hypoglycemia: trial of feeding first. Symptomatic or glucose <1.8 mmol/L: IV dextrose immediately. Persistent hypoglycemia (>48h): investigate for hyperinsulinism, pituitary, or metabolic causes.',4,'apply',['neonatal hypoglycemia','glucose','IDM','dextrose','pediatrics']);
add('peds-neonate','A term newborn has yellowing of skin at 24 hours of age. What is the concern?','Jaundice in first 24 hours is ALWAYS pathological — most likely hemolytic (ABO incompatibility, Rh incompatibility, G6PD deficiency); urgent bilirubin measurement and investigation','Physiological jaundice appears at 48-72h, peaks day 3-5, resolves by day 2 weeks (term). Pathological jaundice: onset <24h, rate >85 μmol/L/day, total bilirubin >200 μmol/L (or zone-specific threshold), direct hyperbilirubinemia, prolonged (>2 weeks term, >3 weeks preterm). Phototherapy or exchange transfusion depending on levels.',5,'analyze',['neonatal jaundice','hyperbilirubinemia','early jaundice','ABO incompatibility','pediatrics']);
add('peds-neonate','What are the current Canadian recommendations for vitamin K and vitamin D supplementation in newborns?','Vitamin K 1 mg IM (or 2 mg PO x3) immediately after birth to prevent hemorrhagic disease; Vitamin D 800-1000 IU/day oral for exclusively breastfed infants (breast milk has insufficient vitamin D)','CPS recommends universal vitamin K prophylaxis for all newborns — hemorrhagic disease of the newborn (VKDB) is preventable. Vitamin D supplementation for breastfed infants: 800 IU/day (standard) or up to 2000 IU/day for infants in northern communities.',2,'recall',['vitamin K','vitamin D','newborn supplementation','VKDB','pediatrics']);
add('peds-neonate','A 30-week premature infant develops increasing oxygen requirement, grunting, and intercostal retractions at 2 hours of life. CXR shows diffuse ground-glass opacity. Diagnosis and treatment?','Respiratory distress syndrome (RDS) from surfactant deficiency; treat with exogenous surfactant (poractant alpha) + CPAP or mechanical ventilation; antenatal corticosteroids (betamethasone) given to mother to promote surfactant synthesis','RDS is the most common cause of respiratory distress in preterm infants. Severity proportional to prematurity. INSURE strategy (INtubation, SURfactant, Extubation to CPAP) reduces ventilation complications. CPS guidelines: antenatal steroids at 24-34 weeks gestation for anticipated preterm delivery.',4,'apply',['RDS','respiratory distress syndrome','surfactant','prematurity','pediatrics']);
add('peds-neonate','A term newborn born to a GBS-positive mother develops fever, poor feeding, and grunting at 18 hours of age. What is the diagnosis and management?','Early-onset neonatal sepsis (EOS) — most likely Group B Streptococcus; blood culture, CBC, CRP, CSF; empiric IV ampicillin + gentamicin; admit to NICU','SOGC GBS guidelines: universal screening at 35-37 weeks. Intrapartum antibiotic prophylaxis (penicillin G) reduces EOS by 80%. Despite prophylaxis, EOS can still occur. EOS symptoms: poor feeding, temperature instability, respiratory distress, lethargy within 72h of birth.',5,'analyze',['neonatal sepsis','EOS','GBS','ampicillin','pediatrics']);
add('peds-neonate','What is necrotizing enterocolitis (NEC) and in which patients does it occur?','NEC: ischemic/inflammatory bowel necrosis in preterm infants; presents at 2-6 weeks of age with feeding intolerance, abdominal distension, bloody stool, and pneumatosis intestinalis on AXR','NEC is the most common GI emergency in preterm infants. Risk increases with lower gestational age. Pneumatosis intestinalis (gas in bowel wall) and portal venous gas are radiographic signs. Treatment: bowel rest, NG decompression, IV antibiotics, surgery for perforation. Breast milk is protective.',4,'apply',['NEC','necrotizing enterocolitis','premature infant','pneumatosis','pediatrics']);
add('peds-neonate','What is the newborn screening program in Canada and what does it test for?','Varies by province; typically: PKU, congenital hypothyroidism (most common treatable cause of intellectual disability), galactosemia, MSUD, fatty acid oxidation disorders, hemoglobinopathies, CF, SMA — heel prick at 24-48h of age','CPS recommends universal newborn screening. Congenital hypothyroidism: TSH heel prick; treat with levothyroxine within 2 weeks to prevent intellectual disability. PKU: phenylalanine-restricted diet prevents ID. Early detection through newborn screening is cost-effective.',2,'recall',['newborn screening','PKU','congenital hypothyroidism','heel prick','pediatrics']);
add('peds-neonate','A preterm infant at 28 weeks develops apnea and bradycardia. What is the management?','Apnea of prematurity: caffeine citrate (respiratory stimulant) IV/oral; monitor with pulse oximetry; CPAP for recurrent or severe apnea','Apnea of prematurity results from immaturity of respiratory control centers. CAFCA trial: caffeine reduces BPD, neurodevelopmental impairment, and reduces duration of mechanical ventilation. Apnea >20 seconds or associated with bradycardia/desaturation requires intervention.',3,'apply',['apnea of prematurity','caffeine','preterm infant','CPAP','pediatrics']);
add('peds-neonate','A term newborn has passed meconium in utero. At delivery, the baby is depressed with decreased tone. What are the key steps?','Vigorous newborn: routine care; Non-vigorous (poor tone, poor resp effort, HR <100): immediate laryngoscopy and suction of trachea if meconium seen, then PPV if needed','Meconium-stained amniotic fluid (MSAF) occurs in 12% of deliveries. NRP 2021: routine suctioning of non-vigorous infants with MSAF recommended. Meconium aspiration syndrome: respiratory distress + patchy consolidation on CXR — may require surfactant, nitric oxide, or ECMO for severe cases.',4,'apply',['meconium aspiration','NRP','non-vigorous newborn','PPV','pediatrics']);
add('peds-neonate','What is intraventricular hemorrhage (IVH) in premature infants and how is it graded?','IVH: bleeding from germinal matrix into ventricles; Grade I: germinal matrix only; Grade II: IVH without ventricular dilation; Grade III: IVH with ventricular dilation; Grade IV: periventricular hemorrhagic infarction — Grades III-IV associated with poor prognosis','IVH occurs in 25% of infants <28 weeks. Antenatal corticosteroids reduce IVH risk. Head ultrasound in all infants <30 weeks at 7 days and 4 weeks. Hydrocephalus may require VP shunt. Grade I-II: good prognosis; Grade III-IV: increased risk of CP and developmental delay.',3,'recall',['IVH','intraventricular hemorrhage','prematurity','germinal matrix','pediatrics']);
add('peds-neonate','What is congenital hypothyroidism and how is it screened and treated?','Congenital hypothyroidism: TSH elevation on newborn screen (heel prick); treat immediately with levothyroxine 10-15 μg/kg/day — must start within 2 weeks to prevent irreversible intellectual disability','CH is the most common preventable cause of intellectual disability. Most cases (75%) are sporadic (thyroid agenesis or dysgenesis). Symptoms in newborn are often subtle: prolonged jaundice, large fontanelle, poor feeding, constipation, hypotonia. Levothyroxine replacement is life-long.',3,'apply',['congenital hypothyroidism','newborn screening','levothyroxine','intellectual disability prevention','pediatrics']);
add('peds-neonate','What are the key differences in fluid requirements in term vs. preterm neonates?','Term newborn: start 60-80 mL/kg/day D10W; Preterm (<32 weeks): 80-100+ mL/kg/day due to increased insensible losses through immature skin; adjust based on weight, electrolytes, and urine output','Preterm infants have immature renal concentrating ability and high insensible water losses (especially <28 weeks). Monitor serum sodium daily (goal 135-145 mEq/L). Early weight loss of 5-15% is normal. Hypernatremia = insufficient fluids; hyponatremia = excess free water.',3,'apply',['neonatal fluids','fluid management','preterm infant','electrolytes','pediatrics']);
add('peds-neonate','What is the management of a newborn with suspected congenital heart disease presenting with cyanosis at birth?','Hyperoxia test (100% O2 for 10 min): PaO2 remains <150 mmHg = cardiac cyanosis; management: prostaglandin E1 (PGE1/alprostadil) to maintain ductal patency until definitive diagnosis and repair','Prostaglandin E1 maintains ductus arteriosus patency in duct-dependent CHD (TGA, HLHS, critical pulmonary stenosis, coarctation). CXR, ECG, and echocardiography establish diagnosis. Tetralogy of Fallot: boot-shaped heart, decreased pulmonary vascular markings. TGA: egg-on-a-string.',5,'analyze',['congenital heart disease','cyanosis','prostaglandin E1','TGA','pediatrics']);

